}

model Order {
  id         String      @id @default(uuid())
  total      Float
  items      OrderItem[]
}

model OrderItem {
  id        String   @id @default(uuid())
  orderId   String
  order     Order    @relation(fields: [orderId], references: [id])
  menuItemId String
}", "command": "create", "path": "/workspace/prisma/schema.prisma"}

